globalThis.__BQ = {"agizYutak":{"lise":{"kolay":[{"q":"Sindirim ağızda hangi iki şekilde başlar?","steps":[{"t":"Soruyu ayrıştır","a":"Ağızdaki sindirim türleri","d":"Ağız, sindirim sisteminin ilk durağıdır ve burada besinler hem fiziksel hem kimyasal olarak işlenmeye başlar. Bu nedenle ağızda iki farklı sindirim türü eş zamanlı yürür."},{"t":"Mekanik sindirim","a":"Dişlerle parçalama","d":"Dişler besinleri çiğneyerek küçük parçalara ayırır ve dil bu parçaları karıştırır. Böylece besinin yüzey alanı artar ve enzimlerin etki edebileceği geniş bir alan oluşur."},{"t":"Kimyasal sindirim","a":"Tükürük amilazı etkisi","d":"Tükürükteki amilaz (pityalin) enzimi nişastayı parçalamaya başlar. Bu, ağızda gerçekleşen tek kimyasal sindirim olayıdır çünkü amilaz yalnızca karbonhidratlara etki eder."}],"ans":"Mekanik (dişlerle) ve kimyasal (tükürük amilazıyla) sindirim olarak başlar."},{"q":"Tükürükteki amilaz enzimi hangi besini sindirmeye başlar?","steps":[{"t":"Enzimi tanı","a":"Amilaz (pityalin)","d":"Tükürük bezleri tarafından salgılanan amilaz, ağızdaki başlıca sindirim enzimidir. Enzimler etki ettikleri besine göre adlandırılır ve özgül çalışır."},{"t":"Hedef besini belirle","a":"Nişasta (karbonhidrat)","d":"Amilaz nişasta gibi büyük karbonhidratları daha küçük şekerlere (maltoz) parçalar. Bu yüzden uzun süre çiğnenen ekmek tatlanmaya başlar."}],"ans":"Nişastayı (karbonhidratları) sindirmeye başlar."},{"q":"İnsanda kaç çeşit diş bulunur ve görevleri nedir?","steps":[{"t":"Diş çeşitlerini say","a":"Dört çeşit diş","d":"İnsan ağzında kesici, köpek (kanin), küçük azı ve büyük azı olmak üzere dört çeşit diş vardır. Her diş çeşidi farklı bir mekanik işleve uygun şekillenmiştir."},{"t":"Görevleri eşleştir","a":"Kesme, parçalama, öğütme","d":"Kesici dişler besini ısırıp keser, köpek dişleri parçalar, azı dişleri ise öğütür. Bu iş bölümü mekanik sindirimi etkili kılar."}],"ans":"Dört çeşit (kesici, köpek, küçük azı, büyük azı); kesme, parçalama ve öğütme yaparlar."},{"q":"Dilin sindirimdeki temel görevi nedir?","steps":[{"t":"Dilin yapısını düşün","a":"Kaslı organ","d":"Dil, hareketli ve kaslı bir organdır. Bu yapısı sayesinde ağız içinde besinleri farklı yönlere taşıyabilir."},{"t":"Görevini belirle","a":"Karıştırma ve yutmaya yardım","d":"Dil besinleri tükürükle karıştırarak lokma haline getirir ve bu lokmayı yutağa iter. Ayrıca tat almayı da sağlar."}],"ans":"Besini tükürükle karıştırıp lokma yapmak ve yutmaya yardım etmek."},{"q":"Tükürük bezleri tükürüğü nereye salgılar?","steps":[{"t":"Bezi tanı","a":"Tükürük bezleri","d":"Kulak altı, dil altı ve çene altı olmak üzere üç çift tükürük bezi vardır. Bunlar dış salgı bezi olarak çalışır."},{"t":"Salgı yerini belirle","a":"Ağız boşluğu","d":"Tükürük bezleri salgılarını kanallar aracılığıyla ağız boşluğuna döker. Buradaki tükürük hem ıslatma hem de kimyasal sindirim görevi görür."}],"ans":"Ağız boşluğuna salgılar."},{"q":"Yutma sırasında soluk borusunun ağzını kapatan yapı nedir?","steps":[{"t":"Sorunu belirle","a":"Lokmanın yanlış yola kaçma riski","d":"Yutak hem soluk borusuna hem yemek borusuna açılır. Bu yüzden yutma sırasında lokmanın soluk borusuna kaçmaması gerekir."},{"t":"Koruyucu yapıyı bul","a":"Epiglottis (gırtlak kapağı)","d":"Yutma sırasında epiglottis soluk borusunun girişini kapatır. Böylece lokma yemek borusuna yönlendirilir ve boğulma engellenir."}],"ans":"Epiglottis (gırtlak kapağı) kapatır."},{"q":"Yemek borusunda besinler nasıl ilerletilir?","steps":[{"t":"Yapıyı tanı","a":"Kaslı boru","d":"Yemek borusu, çevresinde düz kaslar bulunan bir borudur. Bu kaslar ardı ardına kasılıp gevşeyebilir."},{"t":"Hareketi adlandır","a":"Peristaltik hareket","d":"Kasların dalga şeklinde kasılıp gevşemesine peristaltik hareket denir. Bu hareket lokmayı mideye doğru iter ve yer çekimine bağlı değildir."}],"ans":"Peristaltik (dalga şeklindeki kas) hareketle ilerletilir."},{"q":"Lokma nedir ve nasıl oluşur?","steps":[{"t":"Bileşenleri belirle","a":"Besin + tükürük","d":"Lokma, çiğnenmiş besinin tükürükle karışmasıyla oluşan yumuşak kütledir. Tükürük besini kayganlaştırır."},{"t":"Oluşumunu açıkla","a":"Çiğneme ve karıştırma","d":"Dişler besini parçalar, dil tükürükle karıştırır ve kaygan bir kütle oluşur. Bu lokma kolayca yutulabilir."}],"ans":"Çiğnenmiş besinin tükürükle karışmasıyla oluşan yutulabilir kütledir."},{"q":"Tükürüğün besini ıslatmasının yararı nedir?","steps":[{"t":"Tükürüğün içeriği","a":"Su ve mukus","d":"Tükürük büyük oranda su içerir ve içinde kayganlaştırıcı mukus bulunur. Bu içerik besini nemlendirir."},{"t":"Yararını açıkla","a":"Kolay yutma ve enzim etkisi","d":"Islatılan besin kolayca yutulur ve enzimlerle daha iyi temas eder. Kuru besinin yutulması zor ve sindirimi yavaştır."}],"ans":"Besini kayganlaştırarak yutmayı kolaylaştırır ve enzim etkisini artırır."},{"q":"Ağızda proteinler kimyasal olarak sindirilir mi?","steps":[{"t":"Ağızdaki enzimi hatırla","a":"Yalnızca amilaz","d":"Ağızda etkili olan tek sindirim enzimi tükürük amilazıdır. Bu enzim sadece karbonhidratlara etki eder."},{"t":"Protein durumunu değerlendir","a":"Sindirilmez","d":"Ağızda protein veya yağ sindiren enzim yoktur. Bu nedenle proteinlerin kimyasal sindirimi midede başlar."}],"ans":"Hayır, ağızda protein sindiren enzim olmadığı için sindirilmez."},{"q":"Çiğnemenin kimyasal sindirime katkısı nedir?","steps":[{"t":"Çiğnemenin etkisi","a":"Yüzey alanı artar","d":"Çiğneme besini küçük parçalara böler ve toplam yüzey alanını büyütür. Daha geniş yüzey enzimlere daha çok temas noktası sağlar."},{"t":"Sonucu belirle","a":"Enzimler hızlı etki eder","d":"Yüzey alanı arttıkça amilaz nişastaya daha hızlı etki eder. Böylece mekanik sindirim kimyasal sindirimi destekler."}],"ans":"Yüzey alanını artırarak enzimlerin daha hızlı etki etmesini sağlar."},{"q":"Yutak (farinks) sindirim sisteminde nasıl bir geçittir?","steps":[{"t":"Konumunu belirle","a":"Ağız ile yemek borusu arası","d":"Yutak, ağız boşluğunun gerisinde yer alan kaslı bir geçittir. Hem sindirim hem solunum yolları burada kesişir."},{"t":"İşlevini açıkla","a":"Lokmayı yemek borusuna iletir","d":"Yutma refleksiyle lokma yutaktan yemek borusuna geçer. Bu sırada solunum yolu kapanarak lokmanın doğru yola gitmesi sağlanır."}],"ans":"Ağızdan gelen lokmayı yemek borusuna ileten ortak geçittir."},{"q":"Diş minesinin görevi nedir?","steps":[{"t":"Mineyi tanı","a":"Dişin sert dış tabakası","d":"Mine, dişin en dışındaki ve vücudun en sert dokusudur. Dişin görünen tacını kaplar."},{"t":"Görevini açıkla","a":"Koruma","d":"Mine dişi çiğneme sırasındaki aşınmaya ve mikroplara karşı korur. Mine zarar görürse diş çürükleri başlar."}],"ans":"Dişi aşınma ve dış etkilere karşı koruyan en sert tabakadır."},{"q":"Pityalin başka hangi isimle anılır?","steps":[{"t":"Enzimi tanımla","a":"Tükürük amilazı","d":"Tükürük bezlerinin salgıladığı nişasta sindiren enzime tükürük amilazı denir. Bu enzim karbonhidrat sindiriminde görev alır."},{"t":"Diğer ismini ver","a":"Pityalin","d":"Tükürük amilazının diğer adı pityalindir. İki isim de aynı enzimi ifade eder."}],"ans":"Pityalin, tükürük amilazının diğer adıdır."},{"q":"Sindirimin ilk başladığı organ neresidir?","steps":[{"t":"Sindirim yolunu hatırla","a":"Ağız → yutak → mide...","d":"Sindirim kanalı ağızdan başlar ve anüse kadar uzanır. Besin ilk olarak ağza alınır."},{"t":"İlk organı belirle","a":"Ağız","d":"Hem mekanik hem kimyasal sindirim ilk olarak ağızda başlar. Bu yüzden sindirimin başlangıç organı ağızdır."}],"ans":"Ağız."}],"zor":[{"q":"Bir kişi ekmeği uzun süre çiğnediğinde neden tatlı bir tat hisseder?","steps":[{"t":"Ekmeğin içeriği","a":"Nişasta bakımından zengin","d":"Ekmek temel olarak nişasta içerir ve nişasta tatsızdır. Tat almak için daha küçük şeker moleküllerine ihtiyaç vardır."},{"t":"Enzim etkisi","a":"Amilaz nişastayı parçalar","d":"Uzun çiğneme süresince tükürük amilazı nişastaya etki etmeye devam eder. Enzim nişastayı maltoz gibi küçük şekerlere parçalar."},{"t":"Tat oluşumu","a":"Maltoz tatlıdır","d":"Oluşan maltoz molekülleri tat tomurcukları tarafından algılanır. Bu yüzden çiğneme uzadıkça tatlılık hissi artar."}],"ans":"Amilaz nişastayı maltoza parçaladığı için tatlı tat oluşur."},{"q":"Ağzı kuru olan bir kişide nişasta sindirimi neden yavaşlar?","steps":[{"t":"Tükürüğün rolü","a":"Amilaz taşır","d":"Tükürük, nişastayı sindiren amilaz enzimini içerir. Ayrıca besini ıslatarak enzim temasını kolaylaştırır."},{"t":"Kuruluğun etkisi","a":"Az amilaz, az temas","d":"Ağız kuruysa salgılanan tükürük ve dolayısıyla amilaz miktarı azdır. Kuru besin enzimle iyi karışamaz."},{"t":"Sonuç","a":"Sindirim yavaşlar","d":"Yetersiz amilaz ve zayıf temas nedeniyle nişasta yavaş parçalanır. Bu durum kimyasal sindirimin başlangıcını geciktirir."}],"ans":"Tükürük ve amilaz az olduğu için nişasta sindirimi yavaşlar."},{"q":"Yatağında sırt üstü yatan bir insan neden besinleri yine de mideye iletebilir?","steps":[{"t":"Olası beklenti","a":"Yer çekimi gerekir sanılır","d":"İlk bakışta besinin aşağı inmesi için yer çekimi gerektiği düşünülebilir. Ancak sindirim sistemi buna bağımlı değildir."},{"t":"Gerçek mekanizma","a":"Peristaltik hareket","d":"Yemek borusundaki kaslar dalga şeklinde kasılarak lokmayı iter. Bu peristaltik hareket lokmayı her pozisyonda ileri taşır."},{"t":"Sonuç","a":"Mideye ulaşır","d":"Kas dalgaları lokmayı yer çekimine karşı bile ilerletebilir. Bu yüzden sırt üstü yatan biri de yutabilir."}],"ans":"Peristaltik kas hareketi yer çekiminden bağımsız çalıştığı için."},{"q":"Epiglottis görevini yapmazsa hangi sorun ortaya çıkar?","steps":[{"t":"Epiglottisin görevi","a":"Soluk borusunu kapatma","d":"Yutma sırasında epiglottis soluk borusunun girişini kapatır. Böylece lokma yemek borusuna yönlendirilir."},{"t":"Görev yapılmazsa","a":"Lokma soluk borusuna kaçar","d":"Epiglottis kapanmazsa lokma yanlışlıkla soluk borusuna girebilir. Bu durum solunum yolunu tıkar."},{"t":"Sonuç","a":"Boğulma/öksürük","d":"Soluk borusuna kaçan besin öksürük refleksini tetikler veya boğulmaya yol açabilir. Bu nedenle epiglottis hayati öneme sahiptir."}],"ans":"Lokma soluk borusuna kaçar ve boğulma riski doğar."},{"q":"Bir öğrenci farklı diş çeşitlerinin neden farklı şekillerde olduğunu sorguluyor. Bunun mantığı nedir?","steps":[{"t":"Besin çeşitliliği","a":"Farklı işlemler gerekir","d":"Besinler kesilme, parçalanma ve öğütülme gibi farklı işlemlere ihtiyaç duyar. Tek tip bir diş bunların hepsini verimli yapamaz."},{"t":"Şekil-işlev uyumu","a":"Her diş bir göreve uygun","d":"Kesici dişler ince ve keskin, azı dişleri geniş ve düzdür. Bu şekiller yapacakları işe göre özelleşmiştir."},{"t":"Sonuç","a":"Etkili mekanik sindirim","d":"Farklı diş tipleri birlikte çalışarak besini etkili biçimde işler. Böylece mekanik sindirim verimi yükselir."}],"ans":"Her diş tipi farklı bir mekanik göreve özelleştiği için şekilleri farklıdır."},{"q":"Tükürük salgısı azalan yaşlı bir bireyde sindirim ve yutma neden zorlaşır?","steps":[{"t":"Tükürüğün işlevleri","a":"Islatma ve amilaz","d":"Tükürük besini ıslatır ve amilaz ile nişasta sindirimini başlatır. Bu iki işlev de yeterli tükürüğe bağlıdır."},{"t":"Azalmanın etkisi","a":"Kuru, az enzimli ortam","d":"Tükürük azalınca besin yeterince ıslanmaz ve lokma oluşumu güçleşir. Ayrıca amilaz miktarı düştüğü için nişasta sindirimi azalır."},{"t":"Sonuç","a":"Zor yutma, yavaş sindirim","d":"Kuru lokma yutağa zor ilerler ve kimyasal sindirim zayıflar. Bu yüzden hem yutma hem sindirim zorlaşır."}],"ans":"Islatma ve amilaz azaldığından yutma güçleşir, kimyasal sindirim yavaşlar."},{"q":"Amilaz mide ortamına geçtiğinde neden etkisini büyük ölçüde kaybeder?","steps":[{"t":"Amilazın ortam tercihi","a":"Nötre yakın pH","d":"Tükürük amilazı ağızdaki nötre yakın ortamda en iyi çalışır. Enzimlerin belirli bir optimum pH aralığı vardır."},{"t":"Mide ortamı","a":"Kuvvetli asidik","d":"Mide HCl nedeniyle çok asidiktir ve pH oldukça düşüktür. Bu ortam amilazın çalışma aralığının dışındadır."},{"t":"Sonuç","a":"Enzim inaktive olur","d":"Asidik ortam amilazın yapısını bozar ve enzim işlevini yitirir. Bu yüzden nişasta sindirimi midede durur."}],"ans":"Midenin asidik ortamı amilazı inaktive ettiği için etkisi kaybolur."},{"q":"Çiğnemeden hızlıca yutulan büyük bir lokma neden sindirim sorunu yaratabilir?","steps":[{"t":"Çiğnemenin amacı","a":"Parçalama ve yüzey artışı","d":"Çiğneme besini küçültür ve enzimlerin etki edeceği yüzeyi büyütür. Aynı zamanda tükürükle karışımı sağlar."},{"t":"Çiğnenmeyen lokma","a":"Büyük ve az ıslak","d":"Çiğnenmeden yutulan lokma büyük kalır ve tükürükle yeterince karışmaz. Bu lokma yutağı zorlayabilir."},{"t":"Sonuç","a":"Zor yutma, yavaş sindirim","d":"Büyük parça yemek borusunda takılabilir ve enzimler iç kısma zor ulaşır. Bu da sindirimi yavaşlatır ve yutmayı güçleştirir."}],"ans":"Lokma büyük ve az ıslak kalır; yutma güçleşir, sindirim yavaşlar."},{"q":"Yutma neden hem istemli hem istemsiz bir olay olarak kabul edilir?","steps":[{"t":"İlk evre","a":"İstemli başlatma","d":"Yutmanın başlangıcında lokmayı dilin yutağa itmesi bilinçli kontrol altındadır. Yani kişi yutmayı kendisi başlatır."},{"t":"Sonraki evre","a":"İstemsiz refleks","d":"Lokma yutağa ulaştığında devreye yutma refleksi girer. Bu noktadan sonra peristaltik hareketler otomatik olarak çalışır."},{"t":"Sonuç","a":"İki evreli olay","d":"Başlangıç istemli, devamı istemsizdir. Bu nedenle yutma karma bir süreç olarak tanımlanır."}],"ans":"Başlangıcı istemli, ilerleyişi refleks (istemsiz) olduğu için."},{"q":"Tükürükteki mukusun yemek borusu sağlığı açısından önemi nedir?","steps":[{"t":"Mukusun özelliği","a":"Kayganlaştırıcı","d":"Tükürükteki mukus yapışkan ve kaygan bir maddedir. Besin parçalarını sarar ve yumuşatır."},{"t":"Yemek borusuna etki","a":"Sürtünmeyi azaltır","d":"Kayganlaşan lokma yemek borusu çeperine sürtünmeden ilerler. Bu, çeperin zedelenmesini önler."},{"t":"Sonuç","a":"Koruma ve kolay geçiş","d":"Mukus hem lokmanın kolay geçişini sağlar hem de mukozayı korur. Böylece yemek borusu sağlığı korunur."}],"ans":"Lokmayı kayganlaştırarak yemek borusunu sürtünmeden korur."},{"q":"Bebeklerde süt dişleri varken yetişkinlerde kalıcı dişlerin bulunması neyle açıklanır?","steps":[{"t":"Bebeklik gereksinimi","a":"Küçük çene, az diş","d":"Bebeklerin çenesi küçüktür ve besinleri çoğunlukla yumuşaktır. Bu döneme küçük süt dişleri uygundur."},{"t":"Büyüme süreci","a":"Çene büyür","d":"Çocuk büyüdükçe çene genişler ve daha güçlü çiğneme gerekir. Süt dişleri yetersiz kalır."},{"t":"Sonuç","a":"Kalıcı dişler çıkar","d":"Süt dişleri dökülerek yerlerini daha büyük ve dayanıklı kalıcı dişlere bırakır. Bu, yetişkin beslenmesine uyum sağlar."}],"ans":"Çene büyüdükçe süt dişleri yerini daha güçlü kalıcı dişlere bırakır."},{"q":"Tükürüğün antibakteriyel özelliği sindirim sağlığına nasıl katkı sağlar?","steps":[{"t":"Tükürük içeriği","a":"Bazı koruyucu maddeler","d":"Tükürük, mikroorganizmalara karşı etkili bazı maddeler içerir. Bu maddeler ağız ortamını korur."},{"t":"Etkisi","a":"Mikrop sayısını sınırlar","d":"Bu maddeler ağızdaki bakteri sayısını denetim altında tutar. Böylece besinle alınan mikroplar kısmen etkisizleştirilir."},{"t":"Sonuç","a":"Daha az enfeksiyon","d":"Ağız florasının dengelenmesi diş ve sindirim sağlığını korur. Bu da sindirim sisteminin verimli çalışmasına katkı sağlar."}],"ans":"Ağızdaki mikropları sınırlayarak ağız ve sindirim sağlığını korur."},{"q":"Dilin tat alma görevi beslenme davranışını nasıl etkiler?","steps":[{"t":"Dilin tat işlevi","a":"Tat tomurcukları","d":"Dil üzerindeki tat tomurcukları tatlı, tuzlu, ekşi, acı ve umamiyi algılar. Bu bilgi beyne iletilir."},{"t":"Davranışa etki","a":"Besin seçimi yönlenir","d":"Hoş tatlar besinin yenmesini teşvik ederken acı/bozuk tatlar uyarıcı işlev görür. Bu sayede zararlı besinlerden kaçınılabilir."},{"t":"Sonuç","a":"Güvenli beslenme","d":"Tat algısı hem iştahı hem de zararlı besinden kaçınmayı düzenler. Böylece dil beslenme davranışını yönlendirir."}],"ans":"Tat algısı besin seçimini yönlendirip zararlı besinden kaçınmayı sağlar."},{"q":"Bir besinde sadece protein ve yağ varsa ağızda kimyasal sindirim olur mu?","steps":[{"t":"Ağızdaki enzim","a":"Sadece amilaz","d":"Ağızda yalnızca karbonhidrat sindiren amilaz bulunur. Protein ve yağ sindiren enzim ağızda yoktur."},{"t":"Besin içeriğini değerlendir","a":"Karbonhidrat yok","d":"Besin yalnızca protein ve yağdan oluşuyorsa amilazın etki edeceği nişasta bulunmaz. Dolayısıyla enzim boşta kalır."},{"t":"Sonuç","a":"Kimyasal sindirim olmaz","d":"Bu besinde ağızda yalnızca mekanik sindirim (çiğneme) gerçekleşir. Kimyasal sindirim ise midede başlar."}],"ans":"Hayır; karbonhidrat olmadığından ağızda kimyasal sindirim olmaz, sadece mekanik olur."},{"q":"Peristaltik hareketin tek yönlü olmasının önemi nedir?","steps":[{"t":"Hareketin yönü","a":"Ağızdan mideye","d":"Peristaltik dalgalar normalde lokmayı tek yönde, mideye doğru iter. Kaslar bu yönde sıralı çalışır."},{"t":"Önemini değerlendir","a":"Geri kaçış önlenir","d":"Tek yönlü hareket besinin geri yukarı çıkmasını engeller. Böylece sindirim düzenli bir akış halinde sürer."},{"t":"Sonuç","a":"Verimli ilerleme","d":"Besin her zaman ileri taşındığı için sindirim aşamaları sırayla gerçekleşir. Bu da sindirimin düzenli ilerlemesini sağlar."}],"ans":"Besinin geri kaçmasını önleyip düzenli, ileri yönlü sindirim sağlar."}]}},"mide":{"lise":{"kolay":[{"q":"Midede hangi besinin kimyasal sindirimi başlar?","steps":[{"t":"Mide enzimini hatırla","a":"Pepsin","d":"Midede etkin olan başlıca enzim pepsindir. Pepsin asidik ortamda çalışan bir protein sindirim enzimidir."},{"t":"Hedef besini belirle","a":"Protein","d":"Pepsin büyük protein moleküllerini daha küçük parçalara ayırır. Bu nedenle proteinlerin kimyasal sindirimi midede başlar."}],"ans":"Proteinlerin kimyasal sindirimi midede başlar."},{"q":"Mide özsuyundaki asidin kimyasal adı nedir?","steps":[{"t":"Mide salgısını tanı","a":"Mide özsuyu","d":"Mide bezleri mide özsuyu adı verilen bir salgı üretir. Bu salgı asit, enzim öncüsü ve mukus içerir."},{"t":"Asidi adlandır","a":"Hidroklorik asit","d":"Mide özsuyundaki asit hidroklorik asittir ve kısaca HCl ile gösterilir. Bu asit mide içini çok asidik yapar."}],"ans":"Hidroklorik asit (HCl)."},{"q":"Pepsinojen aktif enzime nasıl dönüşür?","steps":[{"t":"Pepsinojeni tanı","a":"Etkisiz öncül","d":"Pepsinojen, pepsinin etkisiz haldeki öncü molekülüdür. Bu haliyle protein sindiremez."},{"t":"Aktifleşmeyi açıkla","a":"HCl ile aktifleşir","d":"Mide özsuyundaki HCl pepsinojeni etkin enzim olan pepsine dönüştürür. Böylece protein sindirimi başlayabilir."}],"ans":"HCl etkisiyle pepsinojen pepsine dönüşür."},{"q":"HCl mideye giren mikropları nasıl etkiler?","steps":[{"t":"HCl özelliği","a":"Kuvvetli asit","d":"HCl mide içini oldukça asidik yapar. Bu ortam birçok canlı için yaşanmaz."},{"t":"Mikroplara etki","a":"Öldürür","d":"Asidik ortam besinle alınan birçok mikrobu öldürür. Böylece besin kısmen sterilize edilir."}],"ans":"Asidik ortamı sayesinde mikropları öldürür."},{"q":"Midede oluşan bulamaç kıvamındaki besine ne ad verilir?","steps":[{"t":"Mide içeriğini düşün","a":"Besin + mide özsuyu","d":"Midede besin, mide özsuyu ve kas hareketleriyle iyice karışır. Sonuçta yarı sıvı bir karışım oluşur."},{"t":"Karışımı adlandır","a":"Kimus","d":"Bu bulamaç kıvamındaki karışıma kimus denir. Kimus daha sonra ince bağırsağa geçer."}],"ans":"Kimus."},{"q":"Mide hangi sindirim türlerini gerçekleştirir?","steps":[{"t":"Kas hareketi","a":"Mekanik sindirim","d":"Midenin kasları kasılıp gevşeyerek besini çalkalar ve karıştırır. Bu mekanik sindirimdir."},{"t":"Enzim etkisi","a":"Kimyasal sindirim","d":"Pepsin enzimi proteinleri parçalayarak kimyasal sindirim yapar. Böylece midede iki tür sindirim birlikte yürür."}],"ans":"Hem mekanik (kas hareketi) hem kimyasal (pepsin) sindirim."},{"q":"Mide çeperini kendi asidinden koruyan madde nedir?","steps":[{"t":"Tehlikeyi belirle","a":"Asit ve enzim hasarı","d":"Mide içindeki HCl ve pepsin sindirici niteliktedir. Bunlar mide çeperine de zarar verebilir."},{"t":"Koruyucu maddeyi bul","a":"Mukus","d":"Mide çeperi koruyucu bir mukus tabakası salgılar. Bu mukus asit ve enzimin çepere doğrudan değmesini engeller."}],"ans":"Mukus (sümüksü salgı) mide çeperini korur."},{"q":"Mide bezleri nerede bulunur?","steps":[{"t":"Mide yapısını düşün","a":"İç çeper","d":"Midenin iç yüzeyi kıvrımlı bir mukoza ile kaplıdır. Bu yüzeyde salgı yapan yapılar yer alır."},{"t":"Bez konumunu belirle","a":"Mide çeperindeki bezler","d":"Mide bezleri mide çeperinin (mukozanın) içine gömülüdür. Bunlar mide özsuyunu üretir."}],"ans":"Midenin iç çeperinde (mukozasında) bulunur."},{"q":"Midenin kaslı yapısının sindirimdeki rolü nedir?","steps":[{"t":"Kas tabakaları","a":"Güçlü kaslar","d":"Mide çeperinde birden fazla yönde uzanan kas tabakası vardır. Bu kaslar güçlü kasılmalar yapabilir."},{"t":"Rolünü açıkla","a":"Karıştırma","d":"Kaslar besini çalkalayıp mide özsuyuyla iyice karıştırır. Bu mekanik işlem kimyasal sindirimi destekler."}],"ans":"Besini çalkalayıp özsuyla karıştırarak mekanik sindirim yapar."},{"q":"Midede karbonhidrat ve yağ sindirilir mi?","steps":[{"t":"Mide enzimini hatırla","a":"Esas olarak pepsin","d":"Midenin temel sindirim enzimi proteinlere etki eden pepsindir. Mide özellikle protein sindirimine uygundur."},{"t":"Diğer besinleri değerlendir","a":"Yağ-karbonhidrat sindirimi belirgin değil","d":"Midede karbonhidrat ve yağ sindirimi neredeyse gerçekleşmez. Bu besinlerin asıl sindirimi ince bağırsakta tamamlanır."}],"ans":"Belirgin biçimde sindirilmez; midede esas olarak protein sindirimi başlar."},{"q":"Mide özsuyunun üç temel bileşeni nedir?","steps":[{"t":"Salgıları listele","a":"Asit, enzim öncüsü, mukus","d":"Mide bezleri farklı maddeler salgılar. Bunlar birlikte mide özsuyunu oluşturur."},{"t":"Bileşenleri belirle","a":"HCl, pepsinojen, mukus","d":"Mide özsuyu HCl, pepsinojen ve koruyucu mukus içerir. Her biri farklı bir görev üstlenir."}],"ans":"Hidroklorik asit (HCl), pepsinojen ve mukus."},{"q":"Mide neden besinleri bir süre depolar?","steps":[{"t":"Midenin yapısı","a":"Genişleyebilen organ","d":"Mide esnek çeperli, genişleyebilen bir organdır. Bu sayede büyük miktarda besin alabilir."},{"t":"Depolamanın yararı","a":"Kontrollü boşaltım","d":"Mide besini depolayıp yavaş yavaş ince bağırsağa gönderir. Böylece bağırsak aşırı yüklenmez ve sindirim düzenli ilerler."}],"ans":"Besini depolayıp ince bağırsağa kontrollü boşaltmak için."},{"q":"Pepsin hangi pH ortamında en iyi çalışır?","steps":[{"t":"Mide ortamını hatırla","a":"Asidik","d":"Mide HCl nedeniyle kuvvetli asidik bir ortama sahiptir. Pepsin bu ortamda görev yapar."},{"t":"Optimum pH","a":"Düşük (asidik) pH","d":"Pepsin düşük pH değerinde, yani asidik ortamda en etkin çalışır. Bu yüzden HCl pepsin için uygun ortamı sağlar."}],"ans":"Düşük (asidik) pH ortamında en iyi çalışır."},{"q":"Mide ile yemek borusu arasındaki kapı görevli yapı nedir?","steps":[{"t":"Geçişi düşün","a":"Yemek borusu-mide sınırı","d":"Yemek borusu mideye açıldığı yerde kaslı bir halka bulunur. Bu yapı açılıp kapanabilir."},{"t":"Kapakçığı adlandır","a":"Mide girişi kapakçığı (kardia)","d":"Bu kaslı kapakçık lokma geçerken açılır, sonra kapanır. Böylece mide içeriğinin yemek borusuna geri kaçması önlenir."}],"ans":"Mide girişindeki kaslı kapakçık (kardia/sfinkter)."},{"q":"Kimus ince bağırsağa hangi açıklıktan geçer?","steps":[{"t":"Mide çıkışını düşün","a":"Mide-bağırsak sınırı","d":"Midenin ince bağırsağa açıldığı yerde kaslı bir kapı vardır. Bu kapı boşaltımı düzenler."},{"t":"Kapıyı adlandır","a":"Mide çıkışı kapakçığı (pilor)","d":"Pilor kapakçığı açılarak kimusun azar azar ince bağırsağa geçmesini sağlar. Böylece sindirim kontrollü ilerler."}],"ans":"Mide çıkışındaki pilor kapakçığından geçer."}],"zor":[{"q":"Pepsinin etkisiz pepsinojen olarak salgılanmasının önemi nedir?","steps":[{"t":"Pepsinin niteliği","a":"Protein sindirir","d":"Pepsin proteinleri parçalayan güçlü bir enzimdir. Mide bezleri de protein yapılı hücrelerden oluşur."},{"t":"Aktif salgılansaydı","a":"Bezi sindirebilirdi","d":"Eğer enzim doğrudan aktif salgılansaydı üretildiği bezi sindirebilirdi. Bu hücrelere zarar verirdi."},{"t":"Çözüm","a":"Etkisiz öncül olarak salgılanır","d":"Enzim önce etkisiz pepsinojen olarak salgılanır, mide boşluğunda HCl ile aktifleşir. Böylece bez hücreleri kendi enziminden korunur."}],"ans":"Etkisiz salgılanması bezin kendi kendini sindirmesini önler."},{"q":"Antasit (mide asidini nötrleyen) ilaç kullanan birinde protein sindirimi neden aksayabilir?","steps":[{"t":"HCl görevleri","a":"Pepsini aktive eder","d":"HCl hem pepsinojeni pepsine çevirir hem de pepsinin çalışacağı asidik ortamı sağlar. Protein sindirimi bu aside bağımlıdır."},{"t":"Antasidin etkisi","a":"Asidi azaltır","d":"Antasit mide asidini nötrler ve pH yükselir. Bu, asidik ortamı bozar."},{"t":"Sonuç","a":"Pepsin az çalışır","d":"Asit azalınca pepsinojen yeterince aktive olmaz ve pepsin uygun ortam bulamaz. Bu nedenle protein sindirimi aksayabilir."}],"ans":"Asit azalınca pepsin yeterince aktifleşemediği için protein sindirimi aksar."},{"q":"Mide mukusu yetersiz salgılanan bir kişide neden ülser riski artar?","steps":[{"t":"Mukusun görevi","a":"Çeperi korur","d":"Mukus, mide çeperini HCl ve pepsinden koruyan bir tabaka oluşturur. Bu tabaka asidin çepere değmesini engeller."},{"t":"Mukus azalınca","a":"Çeper açıkta kalır","d":"Mukus azaldığında asit ve pepsin doğrudan mide çeperine etki eder. Bu durum dokuyu yıpratır."},{"t":"Sonuç","a":"Yara (ülser) oluşur","d":"Korunmasız çeper asit ve enzim etkisiyle aşınarak yaralanır. Bu yaralara mide ülseri denir."}],"ans":"Mukus azalınca asit-pepsin çeperi aşındırır ve ülser oluşur."},{"q":"Sadece protein içeren bir öğün midede karbonhidratlı öğüne göre kimyasal sindirimde neden daha aktif işlenir?","steps":[{"t":"Mide enzimini hatırla","a":"Pepsin protein sindirir","d":"Midedeki temel kimyasal sindirim enzimi proteinlere özgü pepsindir. Karbonhidrat sindiren etkin enzim midede yoktur."},{"t":"Protein öğünü","a":"Pepsin için ideal","d":"Protein içeren öğün pepsinin doğrudan etki edebileceği besindir. Mide bu besine kuvvetle yanıt verir."},{"t":"Karbonhidrat öğünü","a":"Midede sindirim sınırlı","d":"Karbonhidratlar midede neredeyse sindirilmez, asıl sindirimleri bağırsakta olur. Bu yüzden midedeki kimyasal etkinlik proteine kıyasla düşüktür."}],"ans":"Mide enzimi pepsin sadece proteine etki ettiğinden protein öğünü midede daha aktif sindirilir."},{"q":"Midesi alınmış bir hastada kansızlık (B12 eksikliği) görülmesi nasıl açıklanır?","steps":[{"t":"Midenin ek görevi","a":"B12 emilim faktörü","d":"Mide, B12 vitamininin bağırsaktan emilmesi için gerekli bir faktör salgılar. Bu faktör B12 ile birleşir."},{"t":"Mide alınınca","a":"Faktör salgılanmaz","d":"Mide olmadığında bu faktör üretilemez ve B12 bağırsaktan emilemez. Vitamin besinle alınsa bile vücuda geçemez."},{"t":"Sonuç","a":"B12 eksikliği ve kansızlık","d":"B12 alyuvar üretimi için gereklidir, eksikliğinde kansızlık gelişir. Bu yüzden midesiz hastalarda kansızlık görülür."}],"ans":"Mide B12 emilim faktörünü üretemediği için B12 emilemez ve kansızlık oluşur."},{"q":"Mide kaslarının farklı yönlerde uzanmasının sindirime katkısı nedir?","steps":[{"t":"Kas düzeni","a":"Çok yönlü kaslar","d":"Mide çeperinde boyuna, halka ve eğik yönde kas tabakaları bulunur. Bu kaslar çok yönlü kasılma yapabilir."},{"t":"Etkisini düşün","a":"Güçlü çalkalama","d":"Farklı yönlerde kasılmalar besini her yönden sıkar ve çalkalar. Bu, besinin mide özsuyuyla iyice karışmasını sağlar."},{"t":"Sonuç","a":"Etkili kimus oluşumu","d":"İyi karışmış besin kimusa dönüşür ve enzim teması artar. Böylece kimyasal sindirim hızlanır."}],"ans":"Çok yönlü kasılma besini iyice çalkalayıp kimus oluşumunu ve enzim temasını artırır."},{"q":"Pilor kapakçığı bozulup sürekli açık kalsaydı sindirimde ne olurdu?","steps":[{"t":"Pilorun görevi","a":"Kontrollü boşaltım","d":"Pilor kapakçığı kimusun azar azar ince bağırsağa geçmesini sağlar. Böylece bağırsak aşırı yüklenmez."},{"t":"Sürekli açık olsaydı","a":"Hızlı geçiş","d":"Kapak sürekli açık kalsaydı kimus mideden çok hızlı boşalırdı. Mide besini yeterince işleyemezdi."},{"t":"Sonuç","a":"Eksik sindirim, yük","d":"Az işlenmiş besin bağırsağa dolardı ve bağırsak aşırı yüklenirdi. Bu da sindirim ve emilimi bozardı."}],"ans":"Kimus hızla boşalır, mide besini işleyemez ve bağırsak aşırı yüklenir."},{"q":"HCl salgısı yetersiz bir kişide besinle alınan mikroplar neden daha çok sorun çıkarır?","steps":[{"t":"HCl koruyucu rolü","a":"Mikropları öldürür","d":"HCl midede asidik ortam oluşturarak besinle gelen birçok mikrobu öldürür. Bu doğal bir savunma hattıdır."},{"t":"HCl azalınca","a":"Mikroplar canlı kalır","d":"Asit yetersizse ortam mikropların yaşaması için daha uygun hale gelir. Daha fazla mikrop bağırsağa ulaşır."},{"t":"Sonuç","a":"Enfeksiyon riski artar","d":"Canlı kalan mikroplar bağırsakta çoğalarak enfeksiyon yapabilir. Bu yüzden HCl eksikliği sindirim enfeksiyonu riskini artırır."}],"ans":"Asit azaldığından mikroplar ölmez, bağırsağa ulaşıp enfeksiyon yapar."},{"q":"Mide neden hem asit hem de bu asidi etkisizleştirecek mukus salgılar?","steps":[{"t":"Asidin gerekliliği","a":"Sindirim ve koruma","d":"HCl pepsini aktive eder, asidik ortam sağlar ve mikropları öldürür. Bu yüzden mide güçlü asit üretmek zorundadır."},{"t":"Asidin tehlikesi","a":"Çeperi de yakabilir","d":"Aynı asit ve enzim mide çeperine de zarar verebilir. Çeper protein yapılıdır ve pepsinle sindirilebilir."},{"t":"Çözüm","a":"Mukus tabakası","d":"Mide, çeperi kaplayan mukus salgılayarak kendini asitten korur. Böylece güçlü asit hem işe yarar hem de çepere zarar vermez."}],"ans":"Asit sindirim için gerekli; mukus ise çeperi bu asitten korumak için salgılanır."},{"q":"Mide boş bir öğünden sonra yarı sıvı kimusun oluşması hangi olaylarla açıklanır?","steps":[{"t":"Mekanik etki","a":"Kaslar karıştırır","d":"Mide kasları besini güçlü kasılmalarla çalkalar ve ezer. Böylece katı besin yumuşar."},{"t":"Kimyasal-sıvı etki","a":"Özsu eklenir","d":"Mide özsuyundaki sıvı ve HCl besine karışarak onu sulandırır. Pepsin de proteinleri parçalar."},{"t":"Sonuç","a":"Kimus oluşur","d":"Mekanik karıştırma ve özsu birleşince besin bulamaç kıvamında kimusa dönüşür. Bu kimus bağırsağa geçmeye hazırdır."}],"ans":"Kas hareketleri ve mide özsuyunun karışmasıyla besin yarı sıvı kimusa dönüşür."},{"q":"Pepsinin proteinleri tam aminoasitlere kadar parçalamamasının bir sakıncası var mıdır?","steps":[{"t":"Pepsinin işlevi","a":"Kısmi parçalama","d":"Pepsin proteinleri tamamen değil, daha küçük peptit parçalarına böler. Bu midede yapılan ön sindirimdir."},{"t":"Sürecin devamı","a":"Bağırsakta tamamlanır","d":"Geri kalan parçalanma ince bağırsakta diğer enzimlerle tamamlanır. Böylece sindirim aşamalı ilerler."},{"t":"Sonuç","a":"Sakınca değil, iş bölümü","d":"Bu durum bir eksiklik değil, sindirimin aşamalı iş bölümüdür. Her organ kendi payına düşeni yapar."}],"ans":"Sakıncası yoktur; pepsin ön parçalama yapar, kalan sindirim bağırsakta tamamlanır."},{"q":"Aşırı stresin mide ülserine zemin hazırlaması nasıl açıklanabilir?","steps":[{"t":"Stres etkisi","a":"Asit-mukus dengesi bozulur","d":"Aşırı stres mide asidi salgısını artırabilir ve koruyucu mukus dengesini bozabilir. Bu, çeperin korunmasını zayıflatır."},{"t":"Çeper hasarı","a":"Asit çepere etki eder","d":"Koruma azalıp asit artınca mide çeperi daha çok etki altında kalır. Bu durum dokuyu aşındırır."},{"t":"Sonuç","a":"Ülser zemini","d":"Sürekli korumasız çeper yaralanmaya açık hale gelir. Böylece stres ülser oluşumuna zemin hazırlar."}],"ans":"Stres asit-mukus dengesini bozarak çeperin asitle aşınmasına zemin hazırlar."},{"q":"Mide olmadan da yaşamın sürebilmesi sindirimle ilgili neyi gösterir?","steps":[{"t":"Midenin işlevi","a":"Depolama ve ön sindirim","d":"Mide besini depolar ve protein sindirimini başlatır. Ancak sindirimin tamamını tek başına yapmaz."},{"t":"Diğer organlar","a":"Bağırsak tamamlar","d":"Mide alınınca depolama ve ön sindirim azalır, fakat ince bağırsak ve enzimler işi büyük ölçüde tamamlar. Beslenme küçük ve sık öğünlerle düzenlenir."},{"t":"Sonuç","a":"Sindirim dağıtılmış bir süreç","d":"Bu durum sindirimin tek organa bağlı olmadığını gösterir. Görevler organlar arasında paylaşılmıştır."}],"ans":"Sindirimin tek organa bağlı olmadığını, görevlerin organlar arasında paylaşıldığını gösterir."},{"q":"Mide içeriğinin yemek borusuna kaçması (reflü) neden rahatsızlık verir?","steps":[{"t":"Mide içeriği","a":"Asidik kimus","d":"Mide içeriği HCl nedeniyle kuvvetli asidiktir. Mide çeperi mukusla bu aside karşı korunur."},{"t":"Yemek borusu farkı","a":"Asit koruması zayıf","d":"Yemek borusu çeperi mide gibi güçlü asit korumasına sahip değildir. Asit buraya kaçtığında çeperi tahriş eder."},{"t":"Sonuç","a":"Yanma hissi","d":"Asidin tahriş ettiği yemek borusunda yanma ve rahatsızlık oluşur. Buna halk arasında mide ekşimesi denir."}],"ans":"Asidik içerik koruması zayıf yemek borusunu tahriş ettiği için yanma yapar."},{"q":"Mide bezlerinin farklı hücre tiplerinden oluşması işlevsel olarak neden gereklidir?","steps":[{"t":"Mide salgıları","a":"Asit, enzim öncüsü, mukus","d":"Mide özsuyu HCl, pepsinojen ve mukus gibi farklı maddelerden oluşur. Bunların kimyasal nitelikleri birbirinden çok farklıdır."},{"t":"Hücre özelleşmesi","a":"Her madde için ayrı hücre","d":"Farklı maddeleri tek tip hücrenin verimli üretmesi zordur. Bu yüzden asit üreten, enzim öncüsü üreten ve mukus üreten farklı hücreler bulunur."},{"t":"Sonuç","a":"Dengeli özsu","d":"Her hücre tipi kendi maddesini üreterek dengeli bir mide özsuyu oluşturur. Bu iş bölümü hem sindirimi hem korumayı sağlar."}],"ans":"Farklı maddeleri (asit, enzim öncüsü, mukus) verimli üretmek için ayrı hücre tipleri gereklidir."}]}},"inceBagirsak":{"lise":{"kolay":[{"q":"İnce bağırsağın ilk bölümünün adı nedir?","steps":[{"t":"İnce bağırsak bölümleri","a":"Üç bölüm","d":"İnce bağırsak onikiparmak, boş ve kıvrım bağırsağı olmak üzere bölümlerden oluşur. İlk bölüm mideden sonra gelir."},{"t":"İlk bölümü adlandır","a":"Onikiparmak bağırsağı","d":"Mideden hemen sonraki kısa bölüme onikiparmak bağırsağı (duodenum) denir. Burada pankreas ve safra kanalları açılır."}],"ans":"Onikiparmak bağırsağı (duodenum)."},{"q":"Onikiparmak bağırsağına hangi iki organın salgısı dökülür?","steps":[{"t":"Kanalları düşün","a":"İki kanal açılır","d":"Onikiparmak bağırsağına dışarıdan iki önemli salgı kanalı bağlanır. Bunlar sindirimi destekler."},{"t":"Organları belirle","a":"Pankreas ve karaciğer (safra)","d":"Pankreas sindirim enzimlerini, karaciğer ise safrayı buraya gönderir. Böylece sindirim için gerekli salgılar bir araya gelir."}],"ans":"Pankreas (enzimler) ve karaciğer (safra) salgılarını döker."},{"q":"İnce bağırsakta emilimi sağlayan parmaksı çıkıntılara ne denir?","steps":[{"t":"İç yüzeyi düşün","a":"Çıkıntılı yüzey","d":"İnce bağırsağın iç yüzeyi düz değil, çok sayıda küçük çıkıntıyla kaplıdır. Bu çıkıntılar yüzey alanını artırır."},{"t":"Çıkıntıyı adlandır","a":"Villus","d":"Bu parmaksı çıkıntılara villus denir. Villuslar emilen besinleri kana ve lenfe aktarır."}],"ans":"Villus (tümür)."},{"q":"Sindirim hangi organda tamamlanır?","steps":[{"t":"Sindirim aşamalarını hatırla","a":"Ağız → mide → ince bağırsak","d":"Sindirim ağızda başlar, midede sürer ve son aşamaya ince bağırsakta ulaşır. Her organ bir kısmını yapar."},{"t":"Tamamlanma yerini bul","a":"İnce bağırsak","d":"Karbonhidrat, protein ve yağların sindirimi ince bağırsakta tamamlanır. Buradan sonra emilim başlar."}],"ans":"İnce bağırsakta tamamlanır."},{"q":"Safranın yağlar üzerindeki etkisi nedir?","steps":[{"t":"Safranın özelliği","a":"Yağı küçük damlalara böler","d":"Safra, büyük yağ damlalarını küçük damlacıklara ayırır. Buna emülsifikasyon (yağın parçalanıp dağılması) denir."},{"t":"Yararını belirle","a":"Enzim etkisi artar","d":"Küçük damlacıkların yüzey alanı büyüktür ve yağ sindiren enzimler daha kolay etki eder. Böylece yağ sindirimi hızlanır."}],"ans":"Yağları küçük damlacıklara ayırarak enzim etkisini kolaylaştırır."},{"q":"Emilen besinler hangi yapıya geçer?","steps":[{"t":"Villus yapısı","a":"Kılcal damar ve lenf","d":"Her villusun içinde kılcal kan damarları ve bir lenf damarı bulunur. Bunlar emilen maddeleri taşır."},{"t":"Geçiş yerini belirle","a":"Kan ve lenf","d":"Şeker ve aminoasitler kana, yağ ürünleri ise büyük oranda lenfe geçer. Böylece besinler vücuda dağıtılır."}],"ans":"Villuslardaki kan kılcalları ve lenf damarlarına geçer."},{"q":"Pankreas öz suyu hangi besinlere etki eden enzimler içerir?","steps":[{"t":"Pankreasın görevi","a":"Çok yönlü enzim üretir","d":"Pankreas, ince bağırsağa çok çeşitli sindirim enzimleri gönderir. Bu enzimler farklı besinlere etki eder."},{"t":"Besinleri belirle","a":"Karbonhidrat, protein, yağ","d":"Pankreas öz suyunda karbonhidrat, protein ve yağ sindiren enzimler bulunur. Bu nedenle pankreas sindirim için merkezidir."}],"ans":"Karbonhidrat, protein ve yağ sindiren enzimler içerir."},{"q":"Villus üzerindeki çok daha küçük çıkıntılara ne ad verilir?","steps":[{"t":"Villus yüzeyini düşün","a":"Hücre yüzeyinde çıkıntı","d":"Villusları oluşturan hücrelerin yüzeyinde de minik çıkıntılar vardır. Bunlar gözle görülemeyecek kadar küçüktür."},{"t":"Çıkıntıyı adlandır","a":"Mikrovillus","d":"Bu en küçük çıkıntılara mikrovillus denir. Mikrovilluslar emilim yüzeyini daha da artırır."}],"ans":"Mikrovillus."},{"q":"İnce bağırsağın iç yüzeyinin geniş olması neye yarar?","steps":[{"t":"Yüzeyi düşün","a":"Villus ve mikrovillus","d":"İnce bağırsak iç yüzeyi villus ve mikrovilluslarla çok geniştir. Yüzey alanı normal bir borudan kat kat fazladır."},{"t":"Yararını belirle","a":"Emilim artar","d":"Geniş yüzey daha çok besinin daha hızlı emilmesini sağlar. Böylece besinlerin kana geçişi en üst düzeye çıkar."}],"ans":"Besin emilim yüzeyini artırarak emilimi en üst düzeye çıkarır."},{"q":"Safra hangi organda üretilir?","steps":[{"t":"Safrayı düşün","a":"Yağ sindirimine yardımcı sıvı","d":"Safra, yağların sindirimine yardımcı olan yeşilimsi bir salgıdır. Bir organ tarafından üretilir."},{"t":"Üretim yerini bul","a":"Karaciğer","d":"Safra karaciğerde üretilir ve safra kesesinde depolanır. Gerektiğinde onikiparmak bağırsağına salınır."}],"ans":"Karaciğerde üretilir."},{"q":"İnce bağırsakta hangi sindirim türleri görülür?","steps":[{"t":"Kas hareketi","a":"Mekanik sindirim","d":"İnce bağırsak kasları besini karıştırır ve ilerletir. Bu mekanik sindirimdir."},{"t":"Enzim etkisi","a":"Kimyasal sindirim","d":"Pankreas ve bağırsak enzimleri besinleri en küçük yapı taşlarına çevirir. Böylece hem mekanik hem kimyasal sindirim görülür."}],"ans":"Hem mekanik (kas hareketi) hem kimyasal (enzimler) sindirim."},{"q":"Proteinler sindirim sonunda hangi yapı taşına ayrılır?","steps":[{"t":"Proteinin yapısı","a":"Aminoasit zinciri","d":"Proteinler çok sayıda aminoasidin birleşmesiyle oluşur. Sindirim bu zinciri parçalar."},{"t":"Son ürünü belirle","a":"Aminoasit","d":"İnce bağırsakta protein sindirimi tamamlanır ve aminoasitler açığa çıkar. Bu aminoasitler kana emilir."}],"ans":"Aminoasitlere ayrılır."},{"q":"Karbonhidratlar sindirim sonunda hangi yapı taşına ayrılır?","steps":[{"t":"Karbonhidratın yapısı","a":"Şeker birimleri","d":"Karbonhidratlar küçük şeker birimlerinden oluşur. Sindirim onları en küçük şekere böler."},{"t":"Son ürünü belirle","a":"Glikoz gibi monosakkaritler","d":"İnce bağırsakta karbonhidrat sindirimi tamamlanır ve glikoz gibi basit şekerler oluşur. Bunlar kana emilir."}],"ans":"Glikoz gibi basit şekerlere (monosakkaritlere) ayrılır."},{"q":"Yağlar sindirim sonunda hangi yapı taşlarına ayrılır?","steps":[{"t":"Yağın yapısı","a":"Yağ asidi + gliserol","d":"Yağ molekülleri yağ asitleri ve gliserolden oluşur. Sindirim bu bağları çözer."},{"t":"Son ürünü belirle","a":"Yağ asidi ve gliserol","d":"İnce bağırsakta yağ sindirimi tamamlanır ve yağ asitleri ile gliserol açığa çıkar. Bunlar büyük oranda lenfe emilir."}],"ans":"Yağ asitleri ve gliserole ayrılır."},{"q":"Bağırsak öz suyu nereden salgılanır?","steps":[{"t":"Bağırsak çeperini düşün","a":"İç çeperdeki bezler","d":"İnce bağırsağın iç çeperinde salgı yapan bezler bulunur. Bunlar bağırsak öz suyunu üretir."},{"t":"Salgı yerini belirle","a":"Bağırsak çeperi","d":"Bağırsak öz suyu doğrudan bağırsak çeperinden salgılanır. İçindeki enzimler sindirimi tamamlamaya yardım eder."}],"ans":"İnce bağırsağın iç çeperindeki bezlerden salgılanır."}],"zor":[{"q":"Safra enzim içermediği halde yağ sindirimini neden hızlandırır?","steps":[{"t":"Safranın niteliği","a":"Enzim değil","d":"Safra bir sindirim enzimi içermez, yani kimyasal bağ koparmaz. Görevi fiziksel niteliktedir."},{"t":"Etki mekanizması","a":"Yağı küçük damlacıklara böler","d":"Safra büyük yağ damlalarını küçük damlacıklara dağıtır. Bu işlem yağın toplam yüzey alanını büyütür."},{"t":"Sonuç","a":"Enzim daha hızlı etki eder","d":"Yüzey alanı artınca yağ sindiren enzim daha çok temas noktası bulur. Böylece enzim olmadan da sindirimi dolaylı yoldan hızlandırır."}],"ans":"Yağı küçük damlacıklara bölüp yüzey alanını artırarak enzimin daha hızlı etki etmesini sağlar."},{"q":"Safra kanalı tıkanan bir hastada dışkının yağlı ve açık renkli olması nasıl açıklanır?","steps":[{"t":"Safranın yağa etkisi","a":"Yağı parçalar","d":"Safra yağı küçük damlacıklara bölerek sindirim ve emilimini kolaylaştırır. Kanal tıkanırsa safra bağırsağa ulaşamaz."},{"t":"Yağ sindirimi bozulur","a":"Yağ emilemez","d":"Safra olmadan yağ yeterince parçalanamaz ve emilemez. Emilemeyen yağ dışkıyla atılır."},{"t":"Renk değişimi","a":"Safra pigmenti gelmez","d":"Dışkıya rengini veren safra pigmentleri bağırsağa ulaşamaz. Bu yüzden dışkı hem yağlı hem açık renkli olur."}],"ans":"Safra gelmeyince yağ emilemez (yağlı dışkı) ve pigment gelmediği için renk açılır."},{"q":"Villus ve mikrovillusların birlikte bulunması emilime nasıl katkı sağlar?","steps":[{"t":"Villus etkisi","a":"Yüzeyi katlar","d":"Villuslar bağırsak iç yüzeyini çok sayıda parmaksı çıkıntıyla katlar. Bu, yüzey alanını büyük ölçüde artırır."},{"t":"Mikrovillus etkisi","a":"Yüzeyi daha da artırır","d":"Villus hücrelerinin üzerindeki mikrovilluslar yüzeyi bir kez daha artırır. Böylece toplam emilim alanı katlanır."},{"t":"Sonuç","a":"Çok geniş emilim alanı","d":"İki yapı birlikte devasa bir emilim yüzeyi oluşturur. Bu sayede besinler hızla ve eksiksiz emilebilir."}],"ans":"İkisi birlikte emilim yüzeyini katlayarak hızlı ve eksiksiz emilimi sağlar."},{"q":"Pankreas öz suyu olmazsa yalnızca midedeki sindirimin yetersiz kalmasının nedeni nedir?","steps":[{"t":"Midenin sınırı","a":"Sadece protein ön sindirimi","d":"Mide esas olarak proteinleri kısmen sindirir, karbonhidrat ve yağa belirgin etkisi yoktur. Yani mide sindirimi sınırlıdır."},{"t":"Pankreasın rolü","a":"Üç besine de enzim","d":"Pankreas karbonhidrat, protein ve yağ sindiren enzimleri sağlar. Bu enzimler sindirimi tamamlar."},{"t":"Sonuç","a":"Pankreassız sindirim eksik","d":"Pankreas öz suyu olmadan karbonhidrat ve yağ sindirimi neredeyse yapılamaz. Bu yüzden tek başına mide yeterli olmaz."}],"ans":"Mide yalnızca proteine sınırlı etki ettiğinden, üç besine de enzim sağlayan pankreas olmadan sindirim eksik kalır."},{"q":"Pankreas enzimlerinin onikiparmak bağırsağında etkin çalışması için ortamın nasıl olması gerekir?","steps":[{"t":"Mideden gelen kimus","a":"Asidik","d":"Mideden gelen kimus HCl nedeniyle asidiktir. Pankreas enzimleri ise asidik ortamda iyi çalışmaz."},{"t":"Ortamın düzenlenmesi","a":"Baziklik kazanır","d":"Pankreas ve safra salgıları bağırsak ortamını bazik (alkali) hale getirir. Böylece asidik kimus nötrlenir."},{"t":"Sonuç","a":"Enzimler etkin çalışır","d":"Bazik ortamda pankreas enzimleri en iyi etkinliği gösterir. Bu yüzden ortamın nötr-baziğe çekilmesi şarttır."}],"ans":"Asidik kimusun nötrlenip ortamın bazik hale gelmesi gerekir."},{"q":"Sindirimin son ürünleri kana geçerken yağ ürünlerinin farklı yol izlemesi neyle açıklanır?","steps":[{"t":"Şeker ve aminoasit yolu","a":"Kan kılcalları","d":"Glikoz ve aminoasitler suda çözünür ve doğrudan villusların kan kılcallarına emilir. Buradan kana karışırlar."},{"t":"Yağ ürünlerinin durumu","a":"Suda az çözünür","d":"Yağ asitleri ve gliserolden oluşan yağ ürünleri kanla taşınmaya pek uygun değildir. Bu yüzden farklı bir yola yönlendirilir."},{"t":"Sonuç","a":"Lenf damarına geçer","d":"Yağ ürünleri büyük oranda villuslardaki lenf damarına emilir, sonra dolaşıma katılır. Bu yüzden yağlar ayrı bir yol izler."}],"ans":"Yağ ürünleri suda az çözündüğü için kan yerine büyük oranda lenf damarına geçer."},{"q":"İnce bağırsağı çok uzun ve kıvrımlı olan canlılarda emilim neden daha verimlidir?","steps":[{"t":"Uzunluğun etkisi","a":"Daha çok yüzey","d":"Uzun bağırsak daha fazla iç yüzey ve daha çok villus barındırır. Bu, toplam emilim alanını artırır."},{"t":"Temas süresi","a":"Besin uzun kalır","d":"Uzun yolda besin enzimlerle ve emilim yüzeyiyle daha uzun süre temas eder. Bu da emilim için daha çok zaman tanır."},{"t":"Sonuç","a":"Verimli emilim","d":"Hem geniş yüzey hem uzun temas süresi besinlerin daha tam emilmesini sağlar. Bu yüzden uzun bağırsak emilimde avantajlıdır."}],"ans":"Daha geniş yüzey ve daha uzun temas süresi emilimi artırdığı için verimi yükselir."},{"q":"Bir villusun içinde hem kan kılcalı hem lenf damarı bulunmasının mantığı nedir?","steps":[{"t":"Besin çeşitleri","a":"Farklı çözünürlük","d":"Emilen besinler farklı kimyasal özellikte; şeker ve aminoasit suda çözünür, yağ ürünleri çözünmez. Bunların taşınma yolları farklıdır."},{"t":"İki damarın görevi","a":"Ayrı taşıma","d":"Kan kılcalı suda çözünen şeker ve aminoasitleri, lenf damarı ise yağ ürünlerini taşır. Her damar uygun maddeyi alır."},{"t":"Sonuç","a":"Tüm besinler taşınır","d":"İki damarın birlikte bulunması farklı besinlerin aynı villustan etkili taşınmasını sağlar. Böylece hiçbir besin yolda kalmaz."}],"ans":"Suda çözünen besinleri kan, çözünmeyen yağ ürünlerini lenf taşıdığı için ikisi birlikte bulunur."},{"q":"Onikiparmak bağırsağına hem safra hem pankreas öz suyunun açılması sindirim açısından neden avantajlıdır?","steps":[{"t":"İki salgının görevi","a":"Tamamlayıcı işlev","d":"Pankreas enzimleri besinleri kimyasal parçalar, safra ise yağı küçük damlacıklara böler. İki salgı birlikte yağ sindirimini güçlendirir."},{"t":"Aynı bölgeye açılma","a":"Eş zamanlı etki","d":"İkisinin aynı bölgeye dökülmesi salgıların kimusla aynı anda karışmasını sağlar. Böylece safranın hazırladığı yağa enzimler hemen etki eder."},{"t":"Sonuç","a":"Hızlı, eksiksiz sindirim","d":"Eş zamanlı çalışma sindirimi hızlandırır ve verimini artırır. Bu yüzden iki kanalın aynı bölgeye açılması avantajlıdır."}],"ans":"İki salgı eş zamanlı karışarak özellikle yağ sindirimini hızlandırıp eksiksiz hale getirir."},{"q":"Sindirim enzimleri olmadan besinlerin hücre zarından geçememesi neyle açıklanır?","steps":[{"t":"Besin boyutu","a":"Büyük moleküller","d":"Nişasta, protein ve yağ gibi besinler çok büyük moleküllerdir. Bu büyük yapılar hücre zarından geçemez."},{"t":"Enzimin görevi","a":"Küçük birimlere böler","d":"Sindirim enzimleri bu büyük molekülleri glikoz, aminoasit, yağ asidi gibi küçük birimlere ayırır. Küçük moleküller zardan kolayca geçer."},{"t":"Sonuç","a":"Emilim mümkün olur","d":"Ancak küçük yapı taşları haline gelen besinler villuslardan emilebilir. Bu yüzden enzimler emilim için zorunludur."}],"ans":"Besinler büyük olduğundan, enzimler onları zardan geçebilecek küçük birimlere parçalamadan emilemez."},{"q":"İnce bağırsakta ortamın bazik olması mide ortamına göre neden farklı enzimleri gerektirir?","steps":[{"t":"Mide ortamı","a":"Asidik","d":"Mide HCl ile asidiktir ve oradaki pepsin bu asitte çalışır. Her enzimin uygun bir pH aralığı vardır."},{"t":"Bağırsak ortamı","a":"Bazik","d":"İnce bağırsakta pankreas ve safra ortamı bazik yapar. Asidik enzimler burada çalışamaz."},{"t":"Sonuç","a":"Baziğe uygun enzimler","d":"Bağırsakta bazik ortamda etkin enzimler görev alır. Bu yüzden mide ve bağırsak enzimleri farklıdır."}],"ans":"Ortam asitten baziğe döndüğü için her ortama uygun farklı pH değerinde çalışan enzimler gerekir."},{"q":"Çölyak gibi villusların hasar gördüğü hastalıklarda neden beslenme bozukluğu görülür?","steps":[{"t":"Villusun görevi","a":"Emilim yüzeyi","d":"Villuslar besinlerin emildiği geniş yüzeyi oluşturur. Emilimin büyük kısmı bu çıkıntılarda gerçekleşir."},{"t":"Hasarın etkisi","a":"Yüzey azalır","d":"Villuslar hasar görüp körelirse emilim yüzeyi büyük ölçüde küçülür. Besinler sindirilse bile yeterince emilemez."},{"t":"Sonuç","a":"Beslenme bozukluğu","d":"Emilemeyen besinler vücuda geçemez ve dışkıyla atılır. Bu yüzden kişi yeterli yese de beslenme bozukluğu gelişir."}],"ans":"Villuslar hasar görünce emilim yüzeyi azalır, besinler emilemediği için beslenme bozulur."},{"q":"Sindirimin ağızda başlayıp ince bağırsakta tamamlanması neden aşamalı bir süreçtir?","steps":[{"t":"Farklı ortam ihtiyacı","a":"Her besin farklı","d":"Karbonhidrat, protein ve yağın sindirimi farklı enzim ve pH ortamı gerektirir. Tek bir organda hepsi verimli yapılamaz."},{"t":"Organların iş bölümü","a":"Ağız-mide-bağırsak","d":"Ağız karbonhidratı başlatır, mide proteini başlatır, ince bağırsak hepsini tamamlar. Her organ uygun ortamı sağlar."},{"t":"Sonuç","a":"Aşamalı sindirim","d":"Bu iş bölümü besinlerin her birinin uygun koşulda işlenmesini sağlar. Bu yüzden sindirim aşamalı yürür."}],"ans":"Her besin farklı enzim ve ortam gerektirdiğinden sindirim organlar arasında aşamalı paylaşılır."},{"q":"Pankreas enzimlerinin etkisiz halde salgılanıp bağırsakta aktifleşmesinin önemi nedir?","steps":[{"t":"Enzimlerin niteliği","a":"Protein sindirebilir","d":"Pankreasın protein sindiren enzimleri çok güçlüdür ve pankreas dokusu da proteindir. Aktif salgılanırsa kendi dokusunu sindirebilir."},{"t":"Önlem","a":"Etkisiz salgılanır","d":"Bu enzimler önce etkisiz öncül olarak salgılanır, ancak bağırsakta aktifleşir. Böylece pankreas kendini korur."},{"t":"Sonuç","a":"Pankreas korunur","d":"Aktifleşme bağırsakta olduğu için pankreas dokusu zarar görmez. Bu, organın güvenliğini sağlayan bir mekanizmadır."}],"ans":"Enzimler pankreasta etkisizdir, bağırsakta aktifleşir; böylece pankreas kendi dokusunu sindirmekten korunur."},{"q":"İnce bağırsakta peristaltik hareketin sürmesi sindirim ve emilime nasıl katkı sağlar?","steps":[{"t":"Hareketin etkisi","a":"Karıştırma ve ilerletme","d":"İnce bağırsaktaki kas hareketleri besini enzimlerle karıştırır ve ileri taşır. Bu hem mekanik sindirim hem ilerleyiş sağlar."},{"t":"Emilime katkı","a":"Yüzeyle temas","d":"Karıştırılan besin sürekli yeni emilim yüzeyiyle temas eder. Bu, emilen madde miktarını artırır."},{"t":"Sonuç","a":"Verimli sindirim-emilim","d":"Hareket hem enzim temasını hem emilim temasını artırarak süreci verimli kılar. Aynı zamanda besinin kalın bağırsağa ilerlemesini sağlar."}],"ans":"Besini enzim ve emilim yüzeyiyle karıştırıp ilerleterek sindirim ve emilimi artırır."}]}}};
